class Solution {
    public int[] shortestAlternatingPaths(int n, int[][] redEdges, int[][] blueEdges) {
        List<List<Integer>> red = new ArrayList<>();
        List<List<Integer>> blue = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            red.add(new ArrayList<>());
            blue.add(new ArrayList<>());
        }
        for (int[] edge : redEdges) {
            red.get(edge[0]).add(edge[1]);
        }
        for (int[] edge : blueEdges) {
            blue.get(edge[0]).add(edge[1]);
        }
        int[][] directions = {{0, 1}, {1, 0}};
        int[][] dp = new int[n][2];
        for (int i = 0; i < n; i++) {
            dp[i][0] = dp[i][1] = Integer.MAX_VALUE;
        }
        dp[0][0] = dp[0][1] = 0;
        Queue<int[]> queue = new LinkedList<>();
        queue.offer(new int[] {0, 0});
        queue.offer(new int[] {0, 1});
        while (!queue.isEmpty()) {
            int[] curr = queue.poll();
            int x = curr[0], y = curr[1];
            for (int[] dir : directions) {
                int nx = x + dir[0], ny = y + dir[1];
                if (nx >= 0 && nx < n && ny >= 0 && ny < 2) {
                    if (y == 0 && red.get(nx).contains(curr[0])) continue;
                    if (y == 1 && blue.get(nx).contains(curr[0])) continue;
                    if (dp[nx][ny] > dp[x][y] + 1) {
                        dp[nx][ny] = dp[x][y] + 1;
                        queue.offer(new int[] {nx, ny});
                    }
                }
            }
        }
        int[] ans = new int[n];
        for (int i = 0; i < n; i++) {
            ans[i] = Math.min(dp[i][0], dp[i][1]);
            if (ans[i] == Integer.MAX_VALUE) ans[i] = -1;
        }
        return ans;
    }
}
```

